/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. &IsAuthorized = SecGAMIsAuthByFunctionalityKey.Udp(!'<Check_Is_Authenticated>') If &IsAuthorized
LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lançamento Notas Fiscais"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If not &NfeDtaEms.IsEmpty() print printBlockFilterNfeDtaEms EndIf If not &NfeDtaEms_To.IsEmpty() &NfeDtaEms_To_Description = format('%1 (%2)', "Em.", " - ") print printBlockFilterNfeDtaEms_To EndIf If not &ModCod.IsEmpty() print printBlockFilterModCod EndIf If not &NfeNum.IsEmpty() print printBlockFilterNfeNum EndIf If not &NfePedCod.IsEmpty() print printBlockFilterNfePedCod EndIf If not &NfeNumZero.IsEmpty() &FilterNfeNumZeroValueDescription = '' Do Case Case &NfeNumZero = 1 &FilterNfeNumZeroValueDescription = "TODAS NOTAS"
Case &NfeNumZero = 2 &FilterNfeNumZeroValueDescription = "SOMENTE COM Nº NOTA"
EndCase
print printBlockFilterNfeNumZero EndIf If not &NfeSts.IsEmpty() &FilterNfeStsValueDescription = &NfeSts.EnumerationDescription()
print printBlockFilterNfeSts EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'NFECLIRAZ' &NfeCliRaz1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz1.IsEmpty() &NfeCliRaz = &NfeCliRaz1 print printBlockFilterNfeCliRaz EndIf Case &DynamicFiltersSelector1 = !'NFELCTNOM' &NfeLctNom1.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom1.IsEmpty() &NfeLctNom = &NfeLctNom1 print printBlockFilterNfeLctNom EndIf Case &DynamicFiltersSelector1 = !'NFECLICOD' &NfeCliCod1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod1.IsEmpty() &NfeCliCod = &NfeCliCod1 print printBlockFilterNfeCliCod EndIf Case &DynamicFiltersSelector1 = !'NFEPROTER' &NfeProTer1.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer1.IsEmpty() &FilterNfeProTer1ValueDescription = &NfeProTer1.EnumerationDescription()
&FilterNfeProTerValueDescription = &FilterNfeProTer1ValueDescription print printBlockFilterNfeProTer EndIf Case &DynamicFiltersSelector1 = !'NFECLICNPJ' &NfeCliCnpj1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj1.IsEmpty() &NfeCliCnpj = &NfeCliCnpj1 print printBlockFilterNfeCliCnpj EndIf Case &DynamicFiltersSelector1 = !'NFECOD' &NfeCod1.FromString(&GridStateDynamicFilter.Value) If not &NfeCod1.IsEmpty() &NfeCod = &NfeCod1 print printBlockFilterNfeCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'NFECLIRAZ' &NfeCliRaz2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz2.IsEmpty() &NfeCliRaz = &NfeCliRaz2 print printBlockFilterNfeCliRaz EndIf Case &DynamicFiltersSelector2 = !'NFELCTNOM' &NfeLctNom2.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom2.IsEmpty() &NfeLctNom = &NfeLctNom2 print printBlockFilterNfeLctNom EndIf Case &DynamicFiltersSelector2 = !'NFECLICOD' &NfeCliCod2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod2.IsEmpty() &NfeCliCod = &NfeCliCod2 print printBlockFilterNfeCliCod EndIf Case &DynamicFiltersSelector2 = !'NFEPROTER' &NfeProTer2.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer2.IsEmpty() &FilterNfeProTer2ValueDescription = &NfeProTer2.EnumerationDescription()
&FilterNfeProTerValueDescription = &FilterNfeProTer2ValueDescription print printBlockFilterNfeProTer EndIf Case &DynamicFiltersSelector2 = !'NFECLICNPJ' &NfeCliCnpj2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj2.IsEmpty() &NfeCliCnpj = &NfeCliCnpj2 print printBlockFilterNfeCliCnpj EndIf Case &DynamicFiltersSelector2 = !'NFECOD' &NfeCod2.FromString(&GridStateDynamicFilter.Value) If not &NfeCod2.IsEmpty() &NfeCod = &NfeCod2 print printBlockFilterNfeCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'NFECLIRAZ' &NfeCliRaz3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz3.IsEmpty() &NfeCliRaz = &NfeCliRaz3 print printBlockFilterNfeCliRaz EndIf Case &DynamicFiltersSelector3 = !'NFELCTNOM' &NfeLctNom3.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom3.IsEmpty() &NfeLctNom = &NfeLctNom3 print printBlockFilterNfeLctNom EndIf Case &DynamicFiltersSelector3 = !'NFECLICOD' &NfeCliCod3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod3.IsEmpty() &NfeCliCod = &NfeCliCod3 print printBlockFilterNfeCliCod EndIf Case &DynamicFiltersSelector3 = !'NFEPROTER' &NfeProTer3.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer3.IsEmpty() &FilterNfeProTer3ValueDescription = &NfeProTer3.EnumerationDescription()
&FilterNfeProTerValueDescription = &FilterNfeProTer3ValueDescription print printBlockFilterNfeProTer EndIf Case &DynamicFiltersSelector3 = !'NFECLICNPJ' &NfeCliCnpj3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj3.IsEmpty() &NfeCliCnpj = &NfeCliCnpj3 print printBlockFilterNfeCliCnpj EndIf Case &DynamicFiltersSelector3 = !'NFECOD' &NfeCod3.FromString(&GridStateDynamicFilter.Value) If not &NfeCod3.IsEmpty() &NfeCod = &NfeCod3 print printBlockFilterNfeCod EndIf EndCase If &GridState.DynamicFilters.Count >= 4 &DynamicFiltersEnabled4 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(4) &DynamicFiltersSelector4 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector4 = !'NFECLIRAZ' &NfeCliRaz4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz4.IsEmpty() &NfeCliRaz = &NfeCliRaz4 print printBlockFilterNfeCliRaz EndIf Case &DynamicFiltersSelector4 = !'NFELCTNOM' &NfeLctNom4.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom4.IsEmpty() &NfeLctNom = &NfeLctNom4 print printBlockFilterNfeLctNom EndIf Case &DynamicFiltersSelector4 = !'NFECLICOD' &NfeCliCod4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod4.IsEmpty() &NfeCliCod = &NfeCliCod4 print printBlockFilterNfeCliCod EndIf Case &DynamicFiltersSelector4 = !'NFEPROTER' &NfeProTer4.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer4.IsEmpty() &FilterNfeProTer4ValueDescription = &NfeProTer4.EnumerationDescription()
&FilterNfeProTerValueDescription = &FilterNfeProTer4ValueDescription print printBlockFilterNfeProTer EndIf Case &DynamicFiltersSelector4 = !'NFECLICNPJ' &NfeCliCnpj4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj4.IsEmpty() &NfeCliCnpj = &NfeCliCnpj4 print printBlockFilterNfeCliCnpj EndIf Case &DynamicFiltersSelector4 = !'NFECOD' &NfeCod4.FromString(&GridStateDynamicFilter.Value) If not &NfeCod4.IsEmpty() &NfeCod = &NfeCod4 print printBlockFilterNfeCod EndIf EndCase EndIf EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order NfeFilCod EmpCod FilCod (NfeCod) when &OrderedBy = 1 order FilCod when &OrderedBy = 2 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 2 AND &OrderedDsc = True order NfeCod when &OrderedBy = 3 AND &OrderedDsc = False order (NfeCod) when &OrderedBy = 3 AND &OrderedDsc = True order NfeNum when &OrderedBy = 4 AND &OrderedDsc = False order (NfeNum) when &OrderedBy = 4 AND &OrderedDsc = True order NfePedCod when &OrderedBy = 5 AND &OrderedDsc = False order (NfePedCod) when &OrderedBy = 5 AND &OrderedDsc = True order NfeDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (NfeDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order NfeCliCod when &OrderedBy = 7 AND &OrderedDsc = False order (NfeCliCod) when &OrderedBy = 7 AND &OrderedDsc = True order NfeCliRaz when &OrderedBy = 8 AND &OrderedDsc = False order (NfeCliRaz) when &OrderedBy = 8 AND &OrderedDsc = True order NfeVlrTot when &OrderedBy = 9 AND &OrderedDsc = False order (NfeVlrTot) when &OrderedBy = 9 AND &OrderedDsc = True order NfeSts when &OrderedBy = 10 AND &OrderedDsc = False order (NfeSts) when &OrderedBy = 10 AND &OrderedDsc = True
using DSWWNotasNFCe(&FilCod, &NfeDtaEms, &NfeDtaEms_To, &ModCod, &NfeNum, &NfePedCod , &NfeNumZero, &NfeSts, &DynamicFiltersSelector1, &NfeCliRaz1, &NfeLctNom1, &NfeCliCod1 , &NfeProTer1, &NfeCliCnpj1, &NfeCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &NfeCliRaz2 , &NfeLctNom2, &NfeCliCod2, &NfeProTer2, &NfeCliCnpj2, &NfeCod2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &NfeCliRaz3, &NfeLctNom3, &NfeCliCod3, &NfeProTer3, &NfeCliCnpj3 , &NfeCod3, &DynamicFiltersEnabled4, &DynamicFiltersSelector4, &NfeCliRaz4, &NfeLctNom4, &NfeCliCod4 , &NfeProTer4, &NfeCliCnpj4, &NfeCod4) &NfeStsDescription = NfeSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWNotasNFCeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWNotasNFCeGridState")) Else &GridState.FromXml(&Session.Get(!"WWNotasNFCeGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEDTAEMS" &NfeDtaEms.FromString(&GridStateFilterValue.Value) &NfeDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"MODCOD" &ModCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFENUM" &NfeNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPEDCOD" &NfePedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFENUMZERO" &NfeNumZero.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFESTS" &NfeSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
